import{_ as o,o as i,c as t,a2 as r}from"./chunks/framework.B72_uj9U.js";const d=JSON.parse('{"title":"Chapter 15: Production Polish","description":"Shipping a real tool with error recovery, logging, packaging, cross-compilation, release automation, and user-facing documentation.","frontmatter":{"title":"Chapter 15: Production Polish","description":"Shipping a real tool with error recovery, logging, packaging, cross-compilation, release automation, and user-facing documentation."},"headers":[],"relativePath":"learn/project/15-production-polish/index.md","filePath":"learn/project/15-production-polish/index.md"}'),a={name:"learn/project/15-production-polish/index.md"};function n(l,e,s,c,p,h){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="production-polish" tabindex="-1">Production Polish <a class="header-anchor" href="#production-polish" aria-label="Permalink to &quot;Production Polish&quot;">​</a></h1><p>Building a working coding agent is one thing. Shipping a reliable, installable, well-documented tool that users trust is another challenge entirely. This chapter takes everything you have built and prepares it for the real world. You will add the production hardening, packaging, and distribution infrastructure that separates a prototype from a product.</p><p>The chapter begins with error recovery strategies that handle the unpredictable failures inherent in LLM-powered tools -- network timeouts, malformed responses, and interrupted operations. You will implement structured logging for observability, a robust configuration system, and comprehensive CLI flags. Then you will tackle distribution: packaging with Cargo, cross-compiling for Linux and macOS, creating a Homebrew formula, and automating releases through CI/CD pipelines.</p><p>Performance profiling helps you find and fix bottlenecks. Integration testing gives you confidence that everything works end to end. Finally, you will write user documentation and set up changelog and version management so users know what they are getting with each release. By the end of this chapter, your coding agent will be a polished, shippable product.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Implement robust error recovery for network, API, and filesystem failures</li><li>Build structured logging and a flexible configuration management system</li><li>Package the agent with Cargo and cross-compile for multiple platforms</li><li>Create a Homebrew formula and automate releases with CI/CD</li><li>Profile performance and write integration tests for end-to-end validation</li><li>Produce user documentation, changelogs, and version management workflows</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/project/15-production-polish/01-error-recovery.html">Error Recovery</a></li><li><a href="/project/15-production-polish/02-structured-logging.html">Structured Logging</a></li><li><a href="/project/15-production-polish/03-config-file-management.html">Config File Management</a></li><li><a href="/project/15-production-polish/04-cli-flags-and-options.html">CLI Flags and Options</a></li><li><a href="/project/15-production-polish/05-packaging-with-cargo.html">Packaging with Cargo</a></li><li><a href="/project/15-production-polish/06-cross-compilation.html">Cross Compilation</a></li><li><a href="/project/15-production-polish/07-homebrew-formula.html">Homebrew Formula</a></li><li><a href="/project/15-production-polish/08-release-automation.html">Release Automation</a></li><li><a href="/project/15-production-polish/09-performance-profiling.html">Performance Profiling</a></li><li><a href="/project/15-production-polish/10-integration-testing.html">Integration Testing</a></li><li><a href="/project/15-production-polish/11-user-documentation.html">User Documentation</a></li><li><a href="/project/15-production-polish/12-changelog-management.html">Changelog Management</a></li><li><a href="/project/15-production-polish/13-version-management.html">Version Management</a></li><li><a href="/project/15-production-polish/14-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>All previous chapters: This chapter builds on the complete agent implementation</li></ul>',10)])])}const g=o(a,[["render",n]]);export{d as __pageData,g as default};
